總數:'+rows.length+' 首
====================
';rows.forEach((r,i)=>{let title=r.querySelector('.title-column yt-formatted-string')?.innerText||'未知';let artist=r.querySelectorAll('.secondary-flex-columns yt-formatted-string')[0]?.innerText||'未知';text+=`${i+1}. ${title} - ${artist}
`});let blob=new Blob([text],{type:'text/plain'});let url=URL.createObjectURL(blob);let a=document.createElement('a');a.href=url;a.download='YTM_Likes_List.txt';a.click();URL.revokeObjectURL(url);console.log('完成')})();
